const PATTERNS = [
  { id: 'polite_request_modal', cat: 'polite', template: 'Können/Könnten Sie bitte [Infinitiv]?', meaning: 'Can/could you please [do something]?', register: 'formal', grammar: 'Könnten Sie is softer; Können Sie is more direct but still polite with bitte. With a modal verb, the action stays at the end.', watchOut: 'Use du only with friends or close colleagues: Könntest du bitte ...? or Kannst du bitte ...?', slots: [{ name: 'Infinitiv', examples: ['das wiederholen', 'langsamer sprechen', 'mir helfen'] }], examples: [{ de: 'Könnten Sie bitte langsamer sprechen?', en: 'Could you please speak more slowly?' }, { de: 'Können Sie das bitte wiederholen?', en: 'Can you please repeat that?' }, { de: 'Könnten Sie mir bitte helfen?', en: 'Could you please help me?' }], expectedReply: 'You may hear: Ja, natürlich. Einen Moment. or a short explanation if they cannot do it.', learnerReply: 'Answer with Danke, then repeat the key detail or ask one follow-up question.', practice: 'Make the request once with Können Sie and once softer with Könnten Sie.' },
  { id: 'ask_meaning', cat: 'understanding', template: 'Was bedeutet [Wort/Satz]?', meaning: 'What does [word/sentence] mean?', register: 'neutral', grammar: 'Was means what; bedeutet is the verb and stays in position two.', watchOut: 'For a specific word on paper, say dieses Wort, not diese Wort.', slots: [{ name: 'Wort/Satz', examples: ['dieses Wort', 'diese Abkürzung', 'das hier'] }], examples: [{ de: 'Was bedeutet dieses Wort?', en: 'What does this word mean?' }, { de: 'Was bedeutet diese Abkürzung?', en: 'What does this abbreviation mean?' }, { de: 'Was bedeutet das auf dem Formular?', en: 'What does that mean on the form?' }] },
  { id: 'ask_write_down', cat: 'understanding', template: 'Können Sie [etwas] aufschreiben?', meaning: 'Can you write [something] down?', register: 'formal', grammar: 'Aufschreiben is separable: schreiben ... auf in many tenses; with a modal it stays together at the end.', watchOut: 'Useful for names, addresses, numbers, and official terms.', slots: [{ name: 'etwas', examples: ['das', 'die Adresse', 'den Namen'] }], examples: [{ de: 'Können Sie das bitte aufschreiben?', en: 'Can you write that down, please?' }, { de: 'Können Sie die Adresse aufschreiben?', en: 'Can you write down the address?' }, { de: 'Können Sie den Namen aufschreiben?', en: 'Can you write down the name?' }] },
  { id: 'still_learning', cat: 'understanding', template: 'Ich lerne noch Deutsch.', meaning: 'I am still learning German.', register: 'neutral', grammar: 'Noch means still; it makes the sentence sound honest and not apologetic.', watchOut: 'Do not over-apologize. This phrase is enough to set expectations.', slots: [{ name: 'Sprache', examples: ['Deutsch', 'Englisch', 'die deutsche Sprache'] }], examples: [{ de: 'Ich lerne noch Deutsch.', en: 'I am still learning German.' }, { de: 'Ich spreche noch nicht so gut Deutsch.', en: 'I do not speak German very well yet.' }, { de: 'Ich brauche kurz einen Moment.', en: 'I need a moment.' }] },
  { id: 'not_understood', cat: 'understanding', template: 'Ich habe [nicht alles / das Wort nicht] verstanden.', meaning: 'I did not understand [everything / the word].', register: 'neutral', grammar: 'Spoken past often uses haben + participle: habe verstanden. Put nicht before the part you did not understand.', watchOut: 'Nicht alles is softer than gar nichts.', slots: [{ name: 'object', examples: ['nicht alles', 'das Wort nicht', 'den letzten Satz nicht'] }], examples: [{ de: 'Ich habe nicht alles verstanden.', en: 'I did not understand everything.' }, { de: 'Ich habe den letzten Satz nicht verstanden.', en: 'I did not understand the last sentence.' }, { de: 'Ich habe das Wort nicht verstanden.', en: 'I did not understand the word.' }] },
  { id: 'ask_explain_again', cat: 'understanding', template: 'Können Sie das [anders / kurz] erklären?', meaning: 'Can you explain that [differently / briefly]?', register: 'formal', grammar: 'Das points back to what was just said; anders and kurz change how you want it explained.', watchOut: 'With a person, say: Können Sie mir das erklären? Mir is dative.', slots: [{ name: 'manner', examples: ['anders', 'kurz', 'einfacher'] }], examples: [{ de: 'Können Sie das anders erklären?', en: 'Can you explain that differently?' }, { de: 'Können Sie das kurz erklären?', en: 'Can you explain that briefly?' }, { de: 'Können Sie das einfacher erklären?', en: 'Can you explain that more simply?' }] },
  { id: 'want_appointment', cat: 'appointments', template: 'Ich möchte einen Termin [vereinbaren / buchen].', meaning: 'I would like to make/book an appointment.', register: 'formal', grammar: 'Möchte is polite and practical. When there is a second verb, it goes to the end: vereinbaren or buchen.', watchOut: 'Use this for making a new appointment. Use the reschedule pattern when you already have one.', slots: [{ name: 'action', examples: ['vereinbaren', 'buchen', 'machen'] }], examples: [{ de: 'Ich möchte einen Termin vereinbaren.', en: 'I would like to make an appointment.' }, { de: 'Ich möchte einen Termin zur Anmeldung buchen.', en: 'I would like to book an appointment for registration.' }, { de: 'Ich möchte einen Termin machen.', en: 'I would like to make an appointment.' }], expectedReply: 'You may hear a proposed date, the next free slot, a waiting-list option, or that no appointments are available.', learnerReply: 'Answer with Ja, das passt. or Leider passt das nicht. Haben Sie einen anderen Termin?', practice: 'Ask for a new appointment, then answer one offered time with yes or a polite no.' },
  { id: 'want_polite_action', cat: 'polite', template: 'Ich möchte [Nomen] [Infinitiv].', meaning: 'I would like to [do/get/change something].', register: 'formal', grammar: 'Möchte is a polite want/request. When there is a second verb, it usually goes to the end.', watchOut: 'Keep the action concrete: ändern, bekommen, stoppen, prüfen.', slots: [{ name: 'request', examples: ['meine Adresse ändern', 'eine Kopie bekommen', 'die Zahlung stoppen'] }], examples: [{ de: 'Ich möchte meine Adresse ändern.', en: 'I would like to change my address.' }, { de: 'Ich möchte eine Kopie bekommen.', en: 'I would like to get a copy.' }, { de: 'Ich möchte die Zahlung stoppen.', en: 'I would like to stop the payment.' }], expectedReply: 'You may hear which document, proof, fee, or form is needed before the request can be completed.', learnerReply: 'Give the concrete detail: Es geht um ... Then ask: Welche Unterlagen brauchen Sie?', practice: 'Say the request with one real document, payment, or contract from your life.' },
  { id: 'reschedule_appointment', cat: 'appointments', template: 'Ich würde den Termin gern [verschieben / absagen].', meaning: 'I would like to [reschedule/cancel] the appointment.', register: 'formal', grammar: 'Ich würde gern ... is a polite A2 request pattern. The action verb goes to the end: verschieben, absagen, bestätigen.', watchOut: 'Use absagen for cancel, verschieben for move to another time.', slots: [{ name: 'action', examples: ['verschieben', 'absagen', 'bestätigen'] }], examples: [{ de: 'Ich würde den Termin gern verschieben.', en: 'I would like to reschedule the appointment.' }, { de: 'Ich würde den Termin gern absagen.', en: 'I would like to cancel the appointment.' }, { de: 'Ich würde den Termin gern bestätigen.', en: 'I would like to confirm the appointment.' }], expectedReply: 'You may hear a new appointment proposal, a cancellation confirmation, or a note about a fee or deadline.', learnerReply: 'Confirm clearly: Ja, der neue Termin passt. or Bitte schicken Sie mir eine Bestätigung.', practice: 'Move an appointment to another day, then ask for written confirmation.' },
  { id: 'ask_availability', cat: 'appointments', template: 'Haben Sie [Zeit] noch einen freien Termin?', meaning: 'Do you have an available appointment [at that time]?', register: 'formal', grammar: 'Einen freien Termin is accusative because it is the thing they may have. Put the time phrase before noch.', watchOut: 'Noch makes the question sound realistic: appointments may already be booked.', slots: [{ name: 'Zeit', examples: ['diese Woche', 'morgen Vormittag', 'im Mai'] }], examples: [{ de: 'Haben Sie noch einen freien Termin?', en: 'Do you have an available appointment?' }, { de: 'Haben Sie diese Woche noch einen freien Termin?', en: 'Do you have an available appointment this week?' }, { de: 'Haben Sie morgen Vormittag noch einen freien Termin?', en: 'Do you have an available appointment tomorrow morning?' }], expectedReply: 'You may hear: Leider nicht. Der nächste freie Termin ist ... or Ich kann Sie auf die Warteliste setzen.', learnerReply: 'Answer with the date that works for you, or ask: Gibt es eine Warteliste?', practice: 'Ask for a free appointment this week, then ask for the earliest possible date.' },
  { id: 'works_for_you', cat: 'appointments', template: 'Passt Ihnen [Zeit]?', meaning: 'Does [time] work for you?', register: 'formal', grammar: 'Ihnen is the dative formal you. Informal is dir.', watchOut: 'Use capital Ihnen for formal you.', slots: [{ name: 'Zeit', examples: ['Dienstagvormittag', 'der Termin', '14 Uhr'] }], examples: [{ de: 'Passt Ihnen Dienstagvormittag?', en: 'Does Tuesday morning work for you?' }, { de: 'Passt Ihnen 14 Uhr?', en: 'Does 2 p.m. work for you?' }, { de: 'Passt dir morgen?', en: 'Does tomorrow work for you?' }] },
  { id: 'call_about', cat: 'phone', template: 'Ich rufe wegen [Sache] an.', meaning: 'I am calling about [something].', register: 'formal', grammar: 'Anrufen is separable: ich rufe ... an.', watchOut: 'Wegen usually takes genitive in formal German: wegen meines Termins.', slots: [{ name: 'Sache', examples: ['meines Termins', 'meiner Rechnung', 'Ihrer Nachricht'] }], examples: [{ de: 'Ich rufe wegen meines Termins an.', en: 'I am calling about my appointment.' }, { de: 'Ich rufe wegen meiner Rechnung an.', en: 'I am calling about my bill.' }, { de: 'Ich rufe wegen Ihrer Nachricht an.', en: 'I am calling about your message.' }] },
  { id: 'request_documents', cat: 'admin', template: 'Welche Unterlagen brauche ich?', meaning: 'Which documents do I need?', register: 'formal', grammar: 'Welche changes with the noun. Unterlagen is plural, so welche stays plural.', watchOut: 'Unterlagen means supporting documents, not lesson documents.', slots: [{ name: 'context', examples: ['für den Termin', 'für die Anmeldung', 'für den Antrag'] }], examples: [{ de: 'Welche Unterlagen brauche ich?', en: 'Which documents do I need?' }, { de: 'Welche Unterlagen muss ich mitbringen?', en: 'Which documents do I need to bring?' }, { de: 'Welche Unterlagen fehlen noch?', en: 'Which documents are still missing?' }] },
  { id: 'submit_send', cat: 'admin', template: 'Ich habe [etwas] eingereicht/geschickt.', meaning: 'I submitted/sent [something].', register: 'formal', grammar: 'Perfekt uses habe + participle for actions like submitted, sent, uploaded.', watchOut: 'Eingereicht sounds official; geschickt is general.', slots: [{ name: 'etwas', examples: ['den Antrag', 'die Unterlagen', 'das Formular'] }], examples: [{ de: 'Ich habe den Antrag eingereicht.', en: 'I submitted the application.' }, { de: 'Ich habe die Unterlagen geschickt.', en: 'I sent the documents.' }, { de: 'Ich habe das Formular hochgeladen.', en: 'I uploaded the form.' }] },
  { id: 'written_confirmation', cat: 'admin', template: 'Können Sie mir das schriftlich bestätigen?', meaning: 'Can you send me written confirmation of that?', register: 'formal', grammar: 'Mir is dative: to me. Schriftlich means in written form and is useful when you need proof later.', watchOut: 'Ask for written confirmation after dates, fees, deadlines, cancellations, or promises.', slots: [{ name: 'confirmation', examples: ['das schriftlich bestätigen', 'eine Bestätigung schicken', 'eine Kopie schicken'] }], examples: [{ de: 'Können Sie mir das schriftlich bestätigen?', en: 'Can you confirm that in writing for me?' }, { de: 'Können Sie mir eine Bestätigung schicken?', en: 'Can you send me a confirmation?' }, { de: 'Können Sie mir eine Kopie schicken?', en: 'Can you send me a copy?' }], expectedReply: 'You may hear whether they can send an email, letter, PDF, or portal message.', learnerReply: 'Give your email address slowly, then ask when the confirmation will arrive.', practice: 'Ask for written confirmation, then ask whether it can be sent by email.' },
  { id: 'deadline_until', cat: 'time', template: 'Bis wann muss ich [etwas] [machen]?', meaning: 'By when do I have to [do something]?', register: 'formal', grammar: 'Bis wann asks for a deadline; the second verb goes at the end with muss.', watchOut: 'Frist is a deadline; Termin is an appointment.', slots: [{ name: 'task', examples: ['das einreichen', 'antworten', 'die Rechnung bezahlen'] }], examples: [{ de: 'Bis wann muss ich das einreichen?', en: 'By when do I need to submit this?' }, { de: 'Bis wann muss ich antworten?', en: 'By when do I need to reply?' }, { de: 'Bis wann muss ich die Rechnung bezahlen?', en: 'By when do I need to pay the bill?' }] },
  { id: 'need_noun', cat: 'admin', template: 'Ich brauche [Nomen].', meaning: 'I need [noun].', register: 'neutral', grammar: 'Brauchen takes a direct object, so articles often appear in accusative: einen Termin, eine Bestätigung.', watchOut: 'Direct is okay for practical needs; add bitte or Könnten Sie for more politeness.', slots: [{ name: 'Nomen', examples: ['einen Termin', 'eine Bestätigung', 'Hilfe'] }], examples: [{ de: 'Ich brauche einen Termin.', en: 'I need an appointment.' }, { de: 'Ich brauche eine Bestätigung.', en: 'I need a confirmation.' }, { de: 'Ich brauche Hilfe beim Formular.', en: 'I need help with the form.' }] },
  { id: 'problem_with', cat: 'housing', template: 'Es gibt ein Problem mit [Nomen].', meaning: 'There is a problem with [noun].', register: 'formal', grammar: 'Mit takes dative: mit der Heizung, mit dem Vertrag, mit meinem Konto.', watchOut: 'Use this to start a calm problem report.', slots: [{ name: 'Nomen', examples: ['der Heizung', 'dem Vertrag', 'meinem Konto'] }], examples: [{ de: 'Es gibt ein Problem mit der Heizung.', en: 'There is a problem with the heating.' }, { de: 'Es gibt ein Problem mit dem Vertrag.', en: 'There is a problem with the contract.' }, { de: 'Es gibt ein Problem mit meiner Rechnung.', en: 'There is a problem with my bill.' }] },
  { id: 'not_working', cat: 'housing', template: '[Etwas] funktioniert nicht.', meaning: '[Something] is not working.', register: 'neutral', grammar: 'Put the broken thing first, then funktioniert nicht.', watchOut: 'Kaputt means broken; funktioniert nicht can sound less dramatic.', slots: [{ name: 'Etwas', examples: ['Die Heizung', 'Das Internet', 'Der Aufzug'] }], examples: [{ de: 'Die Heizung funktioniert nicht.', en: 'The heating is not working.' }, { de: 'Das Internet funktioniert nicht.', en: 'The internet is not working.' }, { de: 'Der Aufzug funktioniert nicht.', en: 'The lift is not working.' }] },
  { id: 'since_problem', cat: 'housing', template: 'Seit [Zeit] funktioniert [etwas] nicht.', meaning: '[Something] has not worked since/for [time].', register: 'neutral', grammar: 'Seit describes how long the problem has existed. German often keeps present tense here.', watchOut: 'Use seit gestern for since yesterday; seit drei Tagen for for three days.', slots: [{ name: 'Zeit', examples: ['gestern', 'drei Tagen', 'heute Morgen'] }], examples: [{ de: 'Seit gestern funktioniert die Heizung nicht.', en: 'The heating has not worked since yesterday.' }, { de: 'Seit drei Tagen funktioniert das Internet nicht.', en: 'The internet has not worked for three days.' }, { de: 'Seit heute Morgen funktioniert der Aufzug nicht.', en: 'The lift has not worked since this morning.' }] },
  { id: 'repair_visit', cat: 'housing', template: 'Wann kann jemand zur Reparatur vorbeikommen?', meaning: 'When can someone come by for the repair?', register: 'formal', grammar: 'Vorbeikommen is separable, but after kann it stays as an infinitive at the end.', watchOut: 'Jemand keeps it open: a technician, caretaker, or landlord.', slots: [{ name: 'purpose', examples: ['zur Reparatur', 'zur Kontrolle', 'zum Ablesen'] }], examples: [{ de: 'Wann kann jemand zur Reparatur vorbeikommen?', en: 'When can someone come by for the repair?' }, { de: 'Wann kann jemand zur Kontrolle vorbeikommen?', en: 'When can someone come by to check it?' }, { de: 'Wann kann der Techniker vorbeikommen?', en: 'When can the technician come by?' }] },
  { id: 'would_possible', cat: 'polite', template: 'Kann ich [Nomen] bekommen?', meaning: 'Can I get [noun]?', register: 'formal', grammar: 'Kann ich ... bekommen? is a simple A1/A2 request. Add bitte when you want it softer.', watchOut: 'For offices, name the exact item: eine Kopie, eine Bestätigung, einen neuen Termin.', slots: [{ name: 'Nomen', examples: ['eine Kopie', 'eine Bestätigung', 'einen neuen Termin'] }], examples: [{ de: 'Kann ich eine Kopie bekommen?', en: 'Can I get a copy?' }, { de: 'Kann ich eine Bestätigung bekommen?', en: 'Can I get a confirmation?' }, { de: 'Kann ich einen neuen Termin bekommen?', en: 'Can I get a new appointment?' }] },
  { id: 'permission', cat: 'polite', template: 'Darf ich [Infinitiv]?', meaning: 'May I [do something]?', register: 'neutral', grammar: 'Darf asks for permission. The main verb stays at the end.', watchOut: 'Use Darf ich...? with strangers; Kann ich...? also works but is less permission-focused.', slots: [{ name: 'Infinitiv', examples: ['kurz stören', 'hier warten', 'das Fenster öffnen'] }], examples: [{ de: 'Darf ich kurz stören?', en: 'May I interrupt briefly?' }, { de: 'Darf ich hier warten?', en: 'May I wait here?' }, { de: 'Darf ich das Fenster öffnen?', en: 'May I open the window?' }] },
  { id: 'symptom_since', cat: 'health', template: 'Ich habe seit [Zeit] [Beschwerde].', meaning: 'I have had [symptom] for/since [time].', register: 'neutral', grammar: 'German uses present tense with seit for ongoing symptoms.', watchOut: 'Tell the duration; it helps the doctor judge urgency.', slots: [{ name: 'Beschwerde', examples: ['Kopfschmerzen', 'Fieber', 'Rückenschmerzen'] }], examples: [{ de: 'Ich habe seit drei Tagen Kopfschmerzen.', en: 'I have had headaches for three days.' }, { de: 'Ich habe seit gestern Fieber.', en: 'I have had a fever since yesterday.' }, { de: 'Ich habe seit einer Woche Rückenschmerzen.', en: 'I have had back pain for a week.' }] },
  { id: 'take_medicine', cat: 'health', template: 'Wie oft soll ich [Medizin] nehmen?', meaning: 'How often should I take [medicine]?', register: 'formal', grammar: 'Soll ich asks what you are supposed to do; nehmen stays at the end.', watchOut: 'Ask separately about amount and food timing: Wie viele? Vor oder nach dem Essen?', slots: [{ name: 'Medizin', examples: ['das', 'die Tabletten', 'den Saft'] }], examples: [{ de: 'Wie oft soll ich das nehmen?', en: 'How often should I take this?' }, { de: 'Wie oft soll ich die Tabletten nehmen?', en: 'How often should I take the tablets?' }, { de: 'Wie oft soll ich den Saft nehmen?', en: 'How often should I take the syrup?' }] },
  { id: 'unable_work', cat: 'work', template: 'Ich bin krank und [komme heute nicht].', meaning: 'I am sick and [cannot come in today].', register: 'workplace', grammar: 'Two simple clauses joined by und. The verb stays second in each clause.', watchOut: 'For formal written messages, add a greeting and your name.', slots: [{ name: 'time/action', examples: ['komme heute nicht', 'komme morgen nicht', 'melde mich später'] }], examples: [{ de: 'Ich bin krank und komme heute nicht.', en: 'I am sick and will not come in today.' }, { de: 'Ich bin krank und komme morgen nicht.', en: 'I am sick and will not come in tomorrow.' }, { de: 'Ich bin krank und melde mich später.', en: 'I am sick and will get in touch later.' }] },
  { id: 'work_clarify', cat: 'work', template: 'Können wir kurz klären, [was/wie/wer] ...?', meaning: 'Can we quickly clarify [what/how/who] ...?', register: 'workplace', grammar: 'After klären, the small question can send the verb to the end: was zuerst wichtig ist, wer das macht.', watchOut: 'Kurz makes the request lighter and less confrontational.', slots: [{ name: 'question', examples: ['was zuerst wichtig ist', 'wer das macht', 'wie wir weitermachen'] }], examples: [{ de: 'Können wir kurz klären, was zuerst wichtig ist?', en: 'Can we quickly clarify what is important first?' }, { de: 'Können wir kurz klären, wer das macht?', en: 'Can we quickly clarify who will do that?' }, { de: 'Können wir kurz klären, wie wir weitermachen?', en: 'Can we quickly clarify how we continue?' }], expectedReply: 'You may hear a priority decision, owner, deadline, or request to summarize the issue first.', learnerReply: 'Repeat the decision back: Alles klar, ich mache zuerst ...', practice: 'Ask to clarify what is important first, then repeat the answer in one short sentence.' },
  { id: 'send_followup', cat: 'work', template: 'Ich schicke Ihnen später [etwas].', meaning: 'I will send you [something] later.', register: 'formal', grammar: 'Ihnen is formal dative: to you. Time often comes before the thing sent: Ich schicke Ihnen später eine E-Mail.', watchOut: 'For documents, zuschicken sounds polished: Ich schicke Ihnen die Unterlagen später zu.', slots: [{ name: 'etwas', examples: ['die Unterlagen', 'eine E-Mail', 'den Link'] }], examples: [{ de: 'Ich schicke Ihnen später die Unterlagen.', en: 'I will send you the documents later.' }, { de: 'Ich schicke Ihnen später eine E-Mail.', en: 'I will send you an email later.' }, { de: 'Ich schicke Ihnen später den Link.', en: 'I will send you the link later.' }], expectedReply: 'You may hear a deadline, a preferred email address, or a request to include a reference number.', learnerReply: 'Confirm the channel and timing: Ich schicke es heute Nachmittag per E-Mail.', practice: 'Promise to send one concrete item later and add the channel: per E-Mail or im Portal.' },
  { id: 'transport_goes', cat: 'transport', template: 'Fährt diese Bahn nach [Stadt] / zum [Ort] / zur [Haltestelle]?', meaning: 'Does this train/tram go to [place]?', register: 'neutral', grammar: 'Yes/no questions start with the verb: Fährt ...? Use nach for cities, zum for masculine/neuter places, and zur for feminine places.', watchOut: 'Zum = zu dem; zur = zu der.', slots: [{ name: 'Ort', examples: ['zum Hauptbahnhof', 'nach Köln', 'zur Messe'] }], examples: [{ de: 'Fährt diese Bahn zum Hauptbahnhof?', en: 'Does this train go to the main station?' }, { de: 'Fährt dieser Bus nach Köln?', en: 'Does this bus go to Cologne?' }, { de: 'Fährt die U-Bahn zur Messe?', en: 'Does the U-Bahn go to the trade fair?' }] },
  { id: 'transport_cancelled', cat: 'transport', template: '[Transport] fällt aus.', meaning: '[Train/bus/connection] is cancelled.', register: 'neutral', grammar: 'Ausfallen is separable: der Zug fällt aus.', watchOut: 'Ausfall is cancellation; Verspätung is delay.', slots: [{ name: 'transport', examples: ['mein Zug', 'der Bus', 'die Verbindung'] }], examples: [{ de: 'Mein Zug fällt aus.', en: 'My train is cancelled.' }, { de: 'Der Bus fällt aus.', en: 'The bus is cancelled.' }, { de: 'Die Verbindung fällt aus.', en: 'The connection is cancelled.' }] },
  { id: 'where_change', cat: 'transport', template: 'Wo muss ich umsteigen? / Welche Linie muss ich nehmen?', meaning: 'Where do I need to transfer? / Which line should I take?', register: 'neutral', grammar: 'For a simple question, use Wo muss ich umsteigen? If you need the next line, ask: Welche Linie muss ich nehmen?', watchOut: 'For platforms, ask separately: Auf welchem Gleis fährt der Zug ab?', slots: [{ name: 'detail', examples: ['wo', 'welche Linie', 'welchen Bus'] }], examples: [{ de: 'Wo muss ich umsteigen?', en: 'Where do I need to transfer?' }, { de: 'Welche Linie muss ich nehmen?', en: 'Which line should I take?' }, { de: 'In welchen Bus muss ich umsteigen?', en: 'Which bus do I have to change to?' }], expectedReply: 'You may hear a station name, line number, direction, platform, or number of stops.', learnerReply: 'Repeat the route back: Also in ... umsteigen und dann Linie ...?', practice: 'Ask where to transfer, then ask which line to take next.' },
  { id: 'looking_for', cat: 'services', template: 'Ich suche [Nomen].', meaning: 'I am looking for [noun].', register: 'neutral', grammar: 'Suchen takes a direct object: ich suche die Kasse, einen Briefkasten, eine Filiale.', watchOut: 'Do not add nach after suchen in standard German.', slots: [{ name: 'Nomen', examples: ['die Kasse', 'einen Briefkasten', 'eine Packstation'] }], examples: [{ de: 'Ich suche die Kasse.', en: 'I am looking for the checkout.' }, { de: 'Ich suche einen Briefkasten.', en: 'I am looking for a mailbox.' }, { de: 'Ich suche eine Packstation.', en: 'I am looking for a parcel locker.' }] },
  { id: 'exchange_return', cat: 'services', template: 'Ich möchte [etwas] umtauschen/zurückgeben.', meaning: 'I would like to exchange/return [something].', register: 'formal', grammar: 'Möchte is polite; the action verb goes to the end.', watchOut: 'Umtauschen means exchange; zurückgeben means return.', slots: [{ name: 'etwas/action', examples: ['den Artikel umtauschen', 'das zurückgeben', 'die Schuhe zurückgeben'] }], examples: [{ de: 'Ich möchte den Artikel umtauschen.', en: 'I would like to exchange the item.' }, { de: 'Ich möchte das zurückgeben.', en: 'I would like to return this.' }, { de: 'Ich möchte die Schuhe zurückgeben.', en: 'I would like to return the shoes.' }] },
  { id: 'parcel_pickup', cat: 'services', template: 'Ich möchte [Sendung] abholen.', meaning: 'I would like to pick up [a parcel/shipment].', register: 'formal', grammar: 'Abholen is separable, but with möchte it stays at the end.', watchOut: 'Bring ID when the pickup note asks for it.', slots: [{ name: 'Sendung', examples: ['ein Paket', 'einen Brief', 'meine Sendung'] }], examples: [{ de: 'Ich möchte ein Paket abholen.', en: 'I would like to pick up a parcel.' }, { de: 'Ich möchte einen Brief abholen.', en: 'I would like to pick up a letter.' }, { de: 'Ich möchte meine Sendung abholen.', en: 'I would like to pick up my shipment.' }] },
  { id: 'bank_transfer', cat: 'money', template: 'Ich möchte [Geld / Betrag] überweisen.', meaning: 'I would like to transfer [money/amount].', register: 'formal', grammar: 'Überweisen means bank transfer. The receiver often appears with an ... an account/person phrase.', watchOut: 'Do not use schicken for bank transfers; use überweisen.', slots: [{ name: 'object', examples: ['Geld', 'den Betrag', 'die Miete'] }], examples: [{ de: 'Ich möchte Geld überweisen.', en: 'I would like to transfer money.' }, { de: 'Ich möchte die Miete überweisen.', en: 'I would like to transfer the rent.' }, { de: 'Ich möchte den Betrag überweisen.', en: 'I would like to transfer the amount.' }] },
  { id: 'direct_debit', cat: 'money', template: 'Ich zahle per [Zahlungsart].', meaning: 'I pay by [payment method].', register: 'neutral', grammar: 'Per is common for payment method: per Karte, per Lastschrift, per Überweisung.', watchOut: 'Lastschrift means direct debit, not invoice.', slots: [{ name: 'Zahlungsart', examples: ['Karte', 'Lastschrift', 'Überweisung'] }], examples: [{ de: 'Ich zahle per Lastschrift.', en: 'I pay by direct debit.' }, { de: 'Ich zahle per Überweisung.', en: 'I pay by bank transfer.' }, { de: 'Ich zahle per Karte.', en: 'I pay by card.' }] },
  { id: 'social_intro', cat: 'social', template: 'Ich wollte mich kurz vorstellen.', meaning: 'I just wanted to introduce myself briefly.', register: 'neutral', grammar: 'Wollte sounds softer than will. Mich vorstellen is reflexive.', watchOut: 'Good for neighbors, new teams, and local groups.', slots: [{ name: 'context', examples: ['im Haus', 'im Team', 'in der Gruppe'] }], examples: [{ de: 'Ich wollte mich kurz vorstellen.', en: 'I just wanted to introduce myself briefly.' }, { de: 'Ich bin neu im Haus.', en: 'I am new in the building.' }, { de: 'Ich bin neu im Team.', en: 'I am new in the team.' }] },
  { id: 'plan_invite', cat: 'social', template: 'Möchten Sie / Möchtest du [Aktivität]?', meaning: 'Would you like to [do something]?', register: 'mixed', grammar: 'Möchten Sie is formal; möchtest du is informal. It is simpler than Lust haben and good for A1/A2 invitations.', watchOut: 'Use du with friends; use Sie for polite adult distance.', slots: [{ name: 'Aktivität', examples: ['einen Kaffee trinken', 'spazieren gehen', 'mitkommen'] }], examples: [{ de: 'Möchten Sie einen Kaffee trinken?', en: 'Would you like to have a coffee?' }, { de: 'Möchtest du spazieren gehen?', en: 'Would you like to go for a walk?' }, { de: 'Möchtest du mitkommen?', en: 'Would you like to come along?' }] },
  { id: 'let_know', cat: 'social', template: 'Sagen Sie mir bitte / Sag mir Bescheid, wenn [Satz].', meaning: 'Please let me know when/if [sentence].', register: 'formal/informal', grammar: 'Wenn introduces a subordinate clause; the verb goes to the end.', watchOut: 'Formal: Sagen Sie mir bitte Bescheid. Informal: Sag mir Bescheid.', slots: [{ name: 'Satz', examples: ['Sie Zeit haben', 'etwas frei wird', 'du da bist'] }], examples: [{ de: 'Sagen Sie mir bitte Bescheid, wenn Sie Zeit haben.', en: 'Please let me know when you have time.' }, { de: 'Sagen Sie mir bitte Bescheid, wenn etwas frei wird.', en: 'Please let me know if something becomes available.' }, { de: 'Sag mir Bescheid, wenn du da bist.', en: 'Let me know when you are there.' }] },
  { id: 'block_card', cat: 'money', template: 'Können Sie die Karte bitte sperren?', meaning: 'Can you please block the card?', register: 'formal', grammar: 'Sperren means to block or freeze access. The object comes before bitte sperren.', watchOut: 'Use this after a bank card is lost, stolen, or used without permission.', slots: [{ name: 'item', examples: ['die Karte', 'meine Bankkarte', 'die Kreditkarte'] }], examples: [{ de: 'Können Sie die Karte bitte sperren?', en: 'Can you please block the card?' }, { de: 'Können Sie meine Bankkarte sperren?', en: 'Can you block my bank card?' }, { de: 'Ich muss die Karte sperren lassen.', en: 'I need to have the card blocked.' }] },
  { id: 'urgent_help', cat: 'emergency', template: 'Ich brauche dringend [Hilfe / einen Arzt].', meaning: 'I urgently need [help/a doctor].', register: 'neutral', grammar: 'Dringend means urgent and changes the seriousness of the request.', watchOut: 'For immediate danger in Germany/EU, emergency number is 112; police is 110.', slots: [{ name: 'need', examples: ['Hilfe', 'einen Arzt', 'einen Rettungswagen'] }], examples: [{ de: 'Ich brauche dringend Hilfe.', en: 'I urgently need help.' }, { de: 'Ich brauche dringend einen Arzt.', en: 'I urgently need a doctor.' }, { de: 'Ich brauche dringend einen Rettungswagen.', en: 'I urgently need an ambulance.' }] },
];

PATTERNS.push(
  { id: 'give_name', cat: 'understanding', template: 'Ich heiße [Name] / Mein Name ist [Name].', meaning: 'My name is [name].', register: 'neutral', grammar: 'Ich heiße is common and simple. Mein Name ist is useful when someone needs exact record details.', watchOut: 'On the phone, offer to spell the name if it is hard to hear.', slots: [{ name: 'Name', examples: ['Pankaj Singh', 'Anna Müller', 'mein Nachname'] }], examples: [{ de: 'Ich heiße Pankaj Singh.', en: 'My name is Pankaj Singh.' }, { de: 'Mein Name ist Müller.', en: 'My name is Müller.' }, { de: 'Der Termin läuft auf meinen Namen.', en: 'The appointment is under my name.' }] },
  { id: 'give_address', cat: 'admin', template: 'Meine Adresse ist [Adresse].', meaning: 'My address is [address].', register: 'neutral', grammar: 'Adresse is feminine, so meine is correct. Give street, house number, postcode, and city in small parts.', watchOut: 'If the person repeats it incorrectly, correct only the wrong part.', slots: [{ name: 'Adresse', examples: ['Musterstraße 12', '10115 Berlin', 'zweite Etage'] }], examples: [{ de: 'Meine Adresse ist Musterstraße 12.', en: 'My address is Musterstraße 12.' }, { de: 'Die Postleitzahl ist 10115.', en: 'The postcode is 10115.' }, { de: 'Ich wohne im zweiten Stock.', en: 'I live on the second floor.' }] },
  { id: 'give_phone', cat: 'phone', template: 'Meine Telefonnummer ist [Nummer].', meaning: 'My phone number is [number].', register: 'neutral', grammar: 'Telefonnummer is feminine, so meine is correct. Say long numbers in short groups.', watchOut: 'For a mobile number you can also say Handynummer.', slots: [{ name: 'Nummer', examples: ['0176 ...', '+49 ...', 'meine Handynummer'] }], examples: [{ de: 'Meine Telefonnummer ist 0176 ...', en: 'My phone number is 0176 ...' }, { de: 'Meine Handynummer ist ...', en: 'My mobile number is ...' }, { de: 'Können Sie mich unter dieser Nummer zurückrufen?', en: 'Can you call me back at this number?' }] },
  { id: 'need_moment', cat: 'understanding', template: 'Einen Moment, ich [prüfe/schaue] kurz.', meaning: 'One moment, I will quickly [check/look].', register: 'neutral', grammar: 'This buys time politely. Kurz makes it sound like you only need a moment.', watchOut: 'Use this instead of freezing silently when you need to check an app, email, or document.', slots: [{ name: 'action', examples: ['schaue nach', 'prüfe das', 'hole die Unterlagen'] }], examples: [{ de: 'Einen Moment, ich schaue kurz nach.', en: 'One moment, I will quickly check.' }, { de: 'Einen Moment, ich prüfe das kurz.', en: 'One moment, I will quickly check that.' }, { de: 'Ich brauche kurz einen Moment.', en: 'I need a moment.' }] },
  { id: 'spell_detail', cat: 'understanding', template: 'Soll ich ... buchstabieren? / Können Sie ... buchstabieren?', meaning: 'Should I spell it? / Can you spell it?', register: 'formal', grammar: 'Use Soll ich when you offer to spell your detail. Use Können Sie when you need the other person to spell something.', watchOut: 'Names, addresses, and codes are often easier if spelled letter by letter.', slots: [{ name: 'Detail', examples: ['meinen Namen', 'die Adresse', 'Ihren Namen'] }], examples: [{ de: 'Soll ich meinen Namen buchstabieren?', en: 'Should I spell my name?' }, { de: 'Soll ich die Adresse buchstabieren?', en: 'Should I spell the address?' }, { de: 'Könnten Sie bitte Ihren Namen buchstabieren?', en: 'Could you please spell your name?' }] },
  { id: 'ask_urgent', cat: 'time', template: 'Ist das [dringend/wichtig]?', meaning: 'Is that [urgent/important]?', register: 'neutral', grammar: 'This yes/no question starts with ist. Use it to decide priority.', watchOut: 'Dringend means urgent; wichtig means important.', slots: [{ name: 'priority', examples: ['dringend', 'wichtig', 'für heute'] }], examples: [{ de: 'Ist das dringend?', en: 'Is that urgent?' }, { de: 'Ist das für heute?', en: 'Is that for today?' }, { de: 'Ist das wichtig für den Termin?', en: 'Is that important for the appointment?' }] },
  { id: 'ask_location', cat: 'services', template: 'Wo ist/sind/stehen [Ort/Dinge]?', meaning: 'Where is/are [place/things]?', register: 'neutral', grammar: 'Use wo ist for one place, wo sind for plural things, and wo stehen for things that stand somewhere.', watchOut: 'Repeat the direction back if you are not sure.', slots: [{ name: 'Ort/Dinge', examples: ['die Kasse', 'die Mülltonnen', 'die Notaufnahme'] }], examples: [{ de: 'Wo ist der Kundenservice?', en: 'Where is customer service?' }, { de: 'Wo stehen die Mülltonnen?', en: 'Where are the trash bins?' }, { de: 'Wo ist die nächste Notaufnahme?', en: 'Where is the nearest emergency department?' }] },
  { id: 'received_item', cat: 'services', template: 'Ich habe [etwas] bekommen.', meaning: 'I received [something].', register: 'neutral', grammar: 'Bekommen means to receive or get. Use habe + bekommen for a completed action.', watchOut: 'Use nicht bekommen when something did not arrive.', slots: [{ name: 'etwas', examples: ['eine Nachricht', 'eine Bestätigung', 'keinen Code'] }], examples: [{ de: 'Ich habe eine Benachrichtigung bekommen.', en: 'I received a notification.' }, { de: 'Ich habe keine Bestätigung bekommen.', en: 'I did not receive a confirmation.' }, { de: 'Ich habe keinen Abholcode bekommen.', en: 'I did not receive a pickup code.' }] },
  { id: 'lost_or_forgot', cat: 'emergency', template: 'Ich habe [etwas] verloren/vergessen.', meaning: 'I lost/forgot [something].', register: 'neutral', grammar: 'Use habe + verloren for lost items and habe + vergessen for forgotten items.', watchOut: 'For stolen items, say wurde gestohlen when you need to report theft.', slots: [{ name: 'etwas', examples: ['meine Karte verloren', 'meine Gesundheitskarte vergessen', 'mein Passwort vergessen'] }], examples: [{ de: 'Ich habe meine Karte verloren.', en: 'I lost my card.' }, { de: 'Ich habe mein Passwort vergessen.', en: 'I forgot my password.' }, { de: 'Ich habe die Gesundheitskarte vergessen.', en: 'I forgot the health insurance card.' }] }
);

