// Final A1/A2 curriculum pass: remove low-yield cards, simplify advanced material,
// and add the missing high-utility cards needed for balanced topic coverage.
const CURRICULUM_REMOVE_IDS = new Set([
  'un11', 'un20', 'un23', 'un24',
  'ad15', 'ad16', 'ad22', 'ad23', 'ad25',
  'ho1', 'ho16',
  'hl17',
  'wk1', 'wk17',
  'sv12', 'sv15',
  'so2', 'so4', 'so6', 'so7', 'so11', 'so12',
  'em2', 'em3', 'em5', 'em16', 'em17'
]);

function findSeedIndex(id) {
  return SENTENCE_SEEDS.findIndex(seed => seed.id === id);
}
function updateSeed(id, patch) {
  const seed = SENTENCE_SEEDS.find(item => item.id === id);
  if (seed) Object.assign(seed, patch);
}
function replaceSeed(id, seed) {
  const index = findSeedIndex(id);
  if (index >= 0) SENTENCE_SEEDS[index] = seed;
}
function addSeed(seed) {
  if (findSeedIndex(seed.id) < 0) SENTENCE_SEEDS.push(seed);
}

for (let i = SENTENCE_SEEDS.length - 1; i >= 0; i--) {
  if (CURRICULUM_REMOVE_IDS.has(SENTENCE_SEEDS[i].id)) SENTENCE_SEEDS.splice(i, 1);
}


